mapper.select:
select * from nx_community_dispatch_driver_duty
where nx_cdd_community_id = #{communityId}
  and nx_cdd_driver_user_id = #{driverUserId}
  and nx_cdd_route_date = #{routeDate}
limit 1

select * from nx_community_dispatch_driver_duty
where nx_cdd_community_id = #{communityId}
  and nx_cdd_route_date = #{routeDate}

select u.*
from nx_community_dispatch_driver_duty d
         inner join nx_community_user u on u.nx_community_user_id = d.nx_cdd_driver_user_id
where d.nx_cdd_community_id = #{communityId}
  and d.nx_cdd_route_date = #{routeDate}
  and d.nx_cdd_status = 'ON_DUTY'
  and u.nx_COU_community_id = #{communityId}
  and (u.nx_COU_admin = 5 or u.nx_COU_role_id = 5)
order by u.nx_community_user_id

mapper.update:
update nx_community_dispatch_driver_duty
nx_cdd_status = #{nxCddStatus}, nx_cdd_checked_in_at = #{nxCddCheckedInAt}, nx_cdd_checked_out_at = #{nxCddCheckedOutAt},
where nx_community_dispatch_driver_duty_id = #{nxCommunityDispatchDriverDutyId}
